#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
const int N=2e6+10,INF=0x3f3f3f3f;
int head[N],des[N<<1],nxt[N<<1],cgt=1,n;
inline void ins(int x,int y)
{
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;
}
int dp[N][3],g[N];//dp[u][0/1/2] u节点连出去i条边，g[u]把u节点炸掉的代价 
//dp[u][0]=dp[v][0]+ \sum dp[v'][1]
int fa[N];inline int fnd(int x){return fa[x]==x?x:fa[x]=fnd(fa[x]);}
inline void dfs(int u,int fa=0)
{
	dp[u][0]=1;dp[u][1]=INF;dp[u][2]=INF;g[u]=2;
	grep(u,i)if(des[i]!=fa)
	{
		int v=des[i];dfs(v,u);
		dp[u][2]+=g[v];
		dp[u][2]=min(dp[u][2],dp[u][1]+min(dp[v][1],dp[v][0])-1);
		dp[u][1]+=g[v];
		dp[u][1]=min(dp[u][1],dp[u][0]+min(dp[v][1],dp[v][0])-1);
		dp[u][0]+=g[v];
		g[u]+=min(min(min(dp[v][0],dp[v][1]),dp[v][2]),g[v]);
		dp[u][0]=min(dp[u][0],INF);
		dp[u][1]=min(dp[u][1],INF);
		dp[u][2]=min(dp[u][2],INF);
		g[u]=min(g[u],INF); 
	}
}
int main()
{
//	FIN("data.in");
//	FOUT("mine.out");
	n=read();int m=read();rep(1,n,i)fa[i]=i;
	rep(1,m,i)
	{
		int x=read(),y=read(),X=fnd(x),Y=fnd(y);
		if(X!=Y)fa[X]=Y;ins(x,y);
	}
	int ans=-1;
	rep(1,n,i)if(fa[i]==i)
	{
		dfs(i);ans+=min(min(min(dp[i][0],dp[i][1]),dp[i][2]),g[i]);
//		printf("Root :: %d\n",i);
	}
//	rep(1,n,i)printf("%d :: %d %d %d %d\n",i,dp[i][0],dp[i][1],dp[i][2],g[i]);
	
	printf("%d\n",ans);
}
